400	size_t mem_t::non_crypto_hash() const {
401	  const_byte_ptr p = data;
402	  int n = size;
403	  uint32_t x = 1;
404	
405	  while (n >= 4) {
406	    uint32_t chunk;
407	    std::memcpy(&chunk, p, sizeof(chunk));
408	    x ^= chunk;
409	    x ^= x << 13;
410	    x ^= x >> 17;
411	    x ^= x << 5;
412	    n -= 4;
413	    p += 4;
414	  }
415	
416	  while (n > 0) {
417	    x ^= *p;
418	    x ^= x << 13;
419	    x ^= x >> 17;
420	    x ^= x << 5;
421	    n--;
422	    p++;
423	  }
424	
425	  return x;
426	}
