566	void bits_t::resize(int count) {
567	  cb_assert(count >= 0 && "bits_t::resize: count must be non-negative");
568	  if (count == bits) return;
569	
570	  // If we're growing, ensure the currently-unused tail bits are cleared before they become "visible".
571	  if (count > bits && bits > 0) bzero_unused();
572	
573	  int n_old = bits_to_limbs(bits);
574	  int n_new = bits_to_limbs(count);
575	  if (n_old == n_new) {
576	    bits = count;
577	    if (bits > 0) bzero_unused();
578	    return;
579	  }
580	
581	  if (count == 0) {
582	    free();
583	    return;
584	  }
585	
586	  limb_t* old_data = data;
587	  bits = count;
588	
589	  data = new limb_t[n_new];
590	  memset(data, 0, n_new * sizeof(limb_t));
591	
592	  int n_copy = std::min(n_old, n_new);
593	  if (n_copy) memmove(data, old_data, n_copy * sizeof(limb_t));
594	  bzero_unused();
595	
596	  if (n_old) {
597	    secure_bzero((byte_ptr)old_data, n_old * int(sizeof(limb_t)));
598	    delete[] old_data;
599	  }
600	}
