604	  int n_new = bits_to_limbs(count);
605	  if (n_old == n_new) {
606	    bits = count;
607	    return;
608	  }
609	
610	  free();
611	  if (count > 0) {
612	    bits = count;
613	    data = new limb_t[n_new];
614	  }
