656	bits_t operator^(const bits_t& src1, const bits_t& src2) {
657	  cb_assert(src1.bits == src2.bits);
658	
659	  bits_t out;
660	  out.alloc(src1.bits);
661	
662	  int n = bits_t::bits_to_limbs(src1.bits);
663	  for (int i = 0; i < n; i++) out.data[i] = src1.data[i] ^ src2.data[i];  // NOLINT
664	
665	  return out;
