668	bits_t& bits_t::operator+=(const bits_t& src2) {
669	  int n1 = count();
670	  int n2 = src2.count();
671	  cb_assert(n1 >= 0 && n2 >= 0);
672	  cb_assert(n2 <= INT_MAX - n1 && "bits_t::operator+=: size overflow");
673	  const int new_count = n1 + n2;
674	
675	  // Special-case self-append: `to_bin()` returns a view into `data`, and `resize()` may reallocate + free the old
676	  // buffer, turning that view into a dangling pointer. This can trigger UAF for `x += x` on the byte-aligned fast path.
677	  if (&src2 == this) {
678	    resize(new_count);
679	    if ((n1 % 8) == 0) {
680	      const int bytes = bits_to_bytes(n1);
681	      // Append the original bytes by copying within the resized buffer.
682	      memmove(byte_ptr(data) + bytes, data, bytes);
683	    } else {
684	      // Bit-level append (no overlap: read from [0..n1), write to [n1..n1+n2)).
685	      for (int i = 0; i < n2; i++) (*this)[n1 + i] = (*this)[i];
686	    }
687	    return *this;
688	  }
689	
690	  mem_t src1_mem = to_bin();
691	  mem_t src2_mem = src2.to_bin();
692	
693	  resize(new_count);
694	  if ((n1 % 8) == 0) {
695	    memmove(byte_ptr(data) + src1_mem.size, src2_mem.data, src2_mem.size);
696	  } else {
697	    for (int i = 0; i < n2; i++) (*this)[n1 + i] = src2[i];
698	  }
699	  return *this;
700	}
701	
702	bits_t bits_t::operator+(const bits_t& src2) const {
703	  int n1 = count();
704	  int n2 = src2.count();
705	  cb_assert(n1 >= 0 && n2 >= 0);
706	  cb_assert(n2 <= INT_MAX - n1 && "bits_t::operator+: size overflow");
707	  const int new_count = n1 + n2;
708	  bits_t dst(new_count);
709	
710	  mem_t dst_mem = dst.to_bin();
711	  mem_t src1_mem = to_bin();
712	  mem_t src2_mem = src2.to_bin();
713	
714	  memmove(dst.data, src1_mem.data, src1_mem.size);
715	  if ((n1 % 8) == 0)
716	    memmove(byte_ptr(dst.data) + src1_mem.size, src2_mem.data, src2_mem.size);
717	  else {
718	    for (int i = 0; i < n2; i++) dst[n1 + i] = src2[i];
719	  }
720	  return dst;
721	}
