240	uint64_t converter_t::convert_code_type(uint64_t code, uint64_t code2, uint64_t code3, uint64_t code4, uint64_t code5,
241	                                        uint64_t code6, uint64_t code7, uint64_t code8) {
242	  uint64_t value = code;
243	  convert(value);
244	  if (is_error()) return 0;
245	  if (!write) {
246	    if (value == code) return value;
247	    if (code2 && value == code2) return value;
248	    if (code3 && value == code3) return value;
249	    if (code4 && value == code4) return value;
250	    if (code5 && value == code5) return value;
251	    if (code6 && value == code6) return value;
252	    if (code7 && value == code7) return value;
253	    if (code8 && value == code8) return value;
254	    set_error();
255	    return 0;
256	  }
257	  return value;
258	}
