148	  template <typename TKey, typename TItem, typename TInst>
149	  void convert_with_instance(std::map<TKey, TItem>& value, const TInst& instance) {
150	    if (!write) value.clear();
151	    uint32_t count = (uint32_t)value.size();
152	    convert_len(count);
153	    if (!write) {
154	      if (count > MAX_CONTAINER_ELEMENTS) {
155	        set_error();
156	        return;
157	      }
158	    }
159	    auto v = value.begin();
160	    for (uint32_t i = 0; i < count && !is_error(); i++) {
161	      if (write) {
162	        TKey key = v->first;
163	        convert(key);
164	        convert(v->second);
165	        v++;
166	      } else {
167	        TKey key;
168	        convert(key);
169	        if (is_error()) return;
170	        auto [ref, is_new] = value.emplace(key, instance);
171	        if (!is_new) {
172	          set_error();
173	          return;
174	        }
175	        convert(ref->second);
176	        if (is_error()) return;
177	      }
178	    }
