185	buf128_t buf128_t::operator<<(unsigned n) const {
186	  cb_assert(n < 128);
187	  if (n == 0) return *this;
188	  uint64_t l = lo();
189	  uint64_t r = hi();
190	  if (n == 64) {
191	    r = l;
192	    l = 0;
193	  } else if (n > 64) {
194	    r = l << (n - 64);
195	    l = 0;
196	  } else {
197	    r <<= n;
198	    r |= l >> (64 - n);
199	    l <<= n;
200	  }
201	  return make(l, r);
202	}
