193	buf256_t
194	buf256_t::caryless_mul(buf128_t a, buf128_t b) {
195	
196	#if defined(__x86_64__) || defined(__aarch64__)
197	#if defined(__x86_64__)
198	  buf128_t c{};
199	  c.value = _mm_clmulepi64_si128(a.value, b.value, 0x00);
200	  buf128_t e{};
201	  e.value = _mm_clmulepi64_si128(a.value, b.value, 0x10);
202	  buf128_t f{};
203	  f.value = _mm_clmulepi64_si128(a.value, b.value, 0x01);
204	  buf128_t d{};
205	  d.value = _mm_clmulepi64_si128(a.value, b.value, 0x11);
206	#else
207	  buf128_t c{};
208	  c.value = (u128_t)vmull_p64(vgetq_lane_u64(uint64x2_t(a.value), 0), vgetq_lane_u64(uint64x2_t(b.value), 0));
209	  buf128_t e{};
210	  e.value = (u128_t)vmull_p64(vgetq_lane_u64(uint64x2_t(a.value), 0), vgetq_lane_u64(uint64x2_t(b.value), 1));
211	  buf128_t f{};
212	  f.value = (u128_t)vmull_p64(vgetq_lane_u64(uint64x2_t(a.value), 1), vgetq_lane_u64(uint64x2_t(b.value), 0));
213	  buf128_t d{};
214	  d.value = (u128_t)vmull_p64(vgetq_lane_u64(uint64x2_t(a.value), 1), vgetq_lane_u64(uint64x2_t(b.value), 1));
215	#endif
216	
217	  uint64_t c0 = c.lo();
218	  uint64_t c1 = c.hi();
219	  uint64_t d0 = d.lo();
220	  uint64_t d1 = d.hi();
221	  uint64_t e0 = e.lo();
222	  uint64_t e1 = e.hi();
223	  uint64_t f0 = f.lo();
224	  uint64_t f1 = f.hi();
225	
226	  uint64_t r0 = c0;
227	  uint64_t r1 = f0 ^ e0 ^ c1;
228	  uint64_t r2 = d0 ^ e1 ^ f1;
229	  uint64_t r3 = d1;
230	
231	  return buf256_t::make(buf128_t::make(r0, r1), buf128_t::make(r2, r3));
232	
233	#else
234	  buf256_t r = ZERO256;
235	  buf256_t m = buf256_t::make(a, ZERO128);
